const input = $input.first().json;
const action = input.action || 'plan_route';

// --- Credential Loading ---
const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgH = { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY };

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.route-planner&cred_key=eq.ors_api_key&select=cred_value',
  headers: pgH
});
if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'OpenRouteService API key not configured. Use add_credential to set it up.' } }];
}
const API_KEY = creds[0].cred_value;
const ORS = 'https://api.openrouteservice.org';
const ORS_H = { 'Authorization': API_KEY, 'Content-Type': 'application/json' };

// --- Shared Helpers ---
async function geocode(text) {
  if (!text || !text.trim()) return null;
  text = text.trim();
  const m = text.match(/^(-?\d+\.?\d*)\s*,\s*(-?\d+\.?\d*)$/);
  if (m) return { lat: parseFloat(m[1]), lon: parseFloat(m[2]), name: text };
  try {
    const r = await helpers.httpRequest({
      method: 'GET',
      url: ORS + '/geocode/search?api_key=' + API_KEY + '&text=' + encodeURIComponent(text) + '&size=1',
      headers: { 'Accept': 'application/json' }
    });
    if (!r.features || r.features.length === 0) return null;
    const f = r.features[0];
    return { lat: f.geometry.coordinates[1], lon: f.geometry.coordinates[0], name: f.properties.label || text };
  } catch (e) {
    return null;
  }
}

async function geocodeMulti(startText, endText, waypointsText) {
  const startGeo = await geocode(startText);
  if (!startGeo) return { error: 'Could not geocode start location: ' + startText };
  const endGeo = await geocode(endText);
  if (!endGeo) return { error: 'Could not geocode destination: ' + endText };
  const coords = [[startGeo.lon, startGeo.lat]];
  const names = [startGeo.name];
  if (waypointsText) {
    const wps = waypointsText.split(';').map(s => s.trim()).filter(s => s);
    for (const wp of wps) {
      const g = await geocode(wp);
      if (!g) return { error: 'Could not geocode waypoint: ' + wp };
      coords.push([g.lon, g.lat]);
      names.push(g.name);
    }
  }
  coords.push([endGeo.lon, endGeo.lat]);
  names.push(endGeo.name);
  return { coords, names, startGeo, endGeo };
}

function fmtDuration(seconds) {
  const h = Math.floor(seconds / 3600);
  const m = Math.round((seconds % 3600) / 60);
  return h > 0 ? h + 'h ' + m + 'min' : m + 'min';
}

// ============================================================
// ACTION: plan_route (ORS)
// ============================================================
if (action === 'plan_route') {
  const startText = input.start;
  const endText = input.end;
  if (!startText || !endText) return [{ json: { error: 'Parameters "start" and "end" are required.' } }];

  const profile = input.profile || 'foot-hiking';
  const validProfiles = ['foot-hiking', 'foot-walking', 'cycling-regular', 'cycling-road', 'cycling-mountain', 'cycling-electric'];
  if (!validProfiles.includes(profile)) {
    return [{ json: { error: 'Invalid profile: ' + profile + '. Use: ' + validProfiles.join(', ') } }];
  }

  const geo = await geocodeMulti(startText, endText, input.waypoints);
  if (geo.error) return [{ json: { error: geo.error } }];

  const body = { coordinates: geo.coords };

  // Call 1: JSON for summary + directions
  let jsonData;
  try {
    jsonData = await helpers.httpRequest({
      method: 'POST',
      url: ORS + '/v2/directions/' + profile,
      headers: ORS_H,
      body: JSON.stringify(body)
    });
  } catch (err) {
    return [{ json: { error: 'Route planning failed: ' + (err.message || err) } }];
  }

  if (!jsonData.routes || jsonData.routes.length === 0) {
    return [{ json: { error: 'No route found between the given locations.' } }];
  }

  // Call 2: GPX
  let gpxData;
  try {
    gpxData = await helpers.httpRequest({
      method: 'POST',
      url: ORS + '/v2/directions/' + profile + '/gpx',
      headers: { 'Authorization': API_KEY, 'Content-Type': 'application/json; charset=utf-8' },
      body: JSON.stringify(body),
      json: false
    });
  } catch (err) {
    return [{ json: { error: 'GPX generation failed: ' + (err.message || err) } }];
  }

  const route = jsonData.routes[0];
  const summary = route.summary;
  const distKm = (summary.distance / 1000).toFixed(1);
  const durStr = fmtDuration(summary.duration);

  let result = 'Route: ' + geo.startGeo.name + ' → ' + geo.endGeo.name + '\n';
  result += 'Profile: ' + profile + '\n';
  result += 'Distance: ' + distKm + ' km\n';
  result += 'Duration: ' + durStr + '\n';
  if (summary.ascent !== undefined) result += 'Elevation gain: ' + Math.round(summary.ascent) + ' m\n';
  if (summary.descent !== undefined) result += 'Elevation loss: ' + Math.round(summary.descent) + ' m\n';

  if (route.segments) {
    result += '\nDirections:\n';
    let stepNum = 1;
    for (const seg of route.segments) {
      for (const step of (seg.steps || [])) {
        const sDist = step.distance >= 1000
          ? (step.distance / 1000).toFixed(1) + ' km'
          : Math.round(step.distance) + ' m';
        result += stepNum + '. ' + step.instruction + ' (' + sDist + ')\n';
        stepNum++;
      }
    }
  }

  result += '\n--- GPX DATA ---\n' + gpxData;
  return [{ json: { result } }];

// ============================================================
// ACTION: plan_route_outdoor (BRouter + ORS Geocoding)
// ============================================================
} else if (action === 'plan_route_outdoor') {
  const startText = input.start;
  const endText = input.end;
  if (!startText || !endText) return [{ json: { error: 'Parameters "start" and "end" are required.' } }];

  const profile = input.profile || 'trekking';
  const validProfiles = ['trekking', 'fastbike', 'trekking-bike', 'mtb', 'safety'];
  if (!validProfiles.includes(profile)) {
    return [{ json: { error: 'Invalid profile: ' + profile + '. Use: ' + validProfiles.join(', ') } }];
  }

  const geo = await geocodeMulti(startText, endText, input.waypoints);
  if (geo.error) return [{ json: { error: geo.error } }];

  // Build BRouter lonlats parameter: lon1,lat1|lon2,lat2|...
  const lonlats = geo.coords.map(c => c[0].toFixed(6) + ',' + c[1].toFixed(6)).join('|');
  const brouterUrl = 'https://brouter.damsy.net/latest/brouter?lonlats=' + lonlats
    + '&profile=' + profile + '&format=gpx';

  let gpxData;
  let usedFallback = false;
  let orsSummary = null;
  try {
    gpxData = await helpers.httpRequest({
      method: 'GET',
      url: brouterUrl,
      headers: { 'Accept': 'application/gpx+xml' },
      json: false
    });
  } catch (brouterErr) {
    // Fallback to ORS
    usedFallback = true;
    const orsProfile = profile === 'trekking' ? 'foot-hiking'
      : profile === 'fastbike' ? 'cycling-road'
      : profile === 'trekking-bike' ? 'cycling-regular'
      : profile === 'mtb' ? 'cycling-mountain'
      : 'foot-hiking';
    try {
      const orsBody = JSON.stringify({ coordinates: geo.coords, elevation: true });
      const jsonData = await helpers.httpRequest({
        method: 'POST',
        url: ORS + '/v2/directions/' + orsProfile,
        headers: ORS_H,
        body: orsBody
      });
      if (jsonData.routes && jsonData.routes[0]) orsSummary = jsonData.routes[0].summary;
      gpxData = await helpers.httpRequest({
        method: 'POST',
        url: ORS + '/v2/directions/' + orsProfile + '/gpx',
        headers: { 'Authorization': API_KEY, 'Content-Type': 'application/json; charset=utf-8' },
        body: orsBody,
        json: false
      });
    } catch (orsErr) {
      return [{ json: { error: 'Both BRouter and ORS routing failed. BRouter: ' + (brouterErr.message || brouterErr) + ' | ORS: ' + (orsErr.message || orsErr) } }];
    }
  }

  // Parse GPX for basic summary
  let totalDist = 0;
  let elevGain = 0;
  let elevLoss = 0;
  let minEle = Infinity;
  let maxEle = -Infinity;

  if (orsSummary) {
    totalDist = orsSummary.distance || 0;
    elevGain = orsSummary.ascent || 0;
    elevLoss = orsSummary.descent || 0;
  } else {
  try {
    const eleMatches = gpxData.match(/<ele>([\d.]+)<\/ele>/g) || [];
    const elevations = eleMatches.map(m => parseFloat(m.replace(/<\/?ele>/g, '')));
    for (let i = 0; i < elevations.length; i++) {
      const e = elevations[i];
      if (e < minEle) minEle = e;
      if (e > maxEle) maxEle = e;
      if (i > 0) {
        const diff = e - elevations[i - 1];
        if (diff > 0) elevGain += diff;
        else elevLoss += Math.abs(diff);
      }
    }

    // Parse trkpt coordinates for distance calculation
    const ptMatches = gpxData.match(/lat="([\d.-]+)"\s+lon="([\d.-]+)"/g) || [];
    const points = ptMatches.map(m => {
      const parts = m.match(/lat="([\d.-]+)"\s+lon="([\d.-]+)"/);
      return { lat: parseFloat(parts[1]), lon: parseFloat(parts[2]) };
    });
    for (let i = 1; i < points.length; i++) {
      const R = 6371000;
      const dLat = (points[i].lat - points[i-1].lat) * Math.PI / 180;
      const dLon = (points[i].lon - points[i-1].lon) * Math.PI / 180;
      const a = Math.sin(dLat/2) * Math.sin(dLat/2)
        + Math.cos(points[i-1].lat * Math.PI / 180) * Math.cos(points[i].lat * Math.PI / 180)
        * Math.sin(dLon/2) * Math.sin(dLon/2);
      totalDist += R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
    }
  } catch (parseErr) {
    // Continue with partial data
  }
  } // end else (BRouter GPX parsing)

  const distKm = (totalDist / 1000).toFixed(1);

  let result = 'Route: ' + geo.startGeo.name + ' → ' + geo.endGeo.name + '\n';
  result += 'Router: ' + (usedFallback ? 'ORS (BRouter unavailable)' : 'BRouter') + '\n';
  result += 'Profile: ' + profile + '\n';
  if (totalDist > 0) result += 'Distance: ' + distKm + ' km\n';
  if (elevGain > 0) result += 'Elevation gain: ' + Math.round(elevGain) + ' m\n';
  if (elevLoss > 0) result += 'Elevation loss: ' + Math.round(elevLoss) + ' m\n';
  if (minEle !== Infinity) result += 'Elevation range: ' + Math.round(minEle) + ' m – ' + Math.round(maxEle) + ' m\n';
  result += '\nNote: BRouter provides GPS track data only (no turn-by-turn directions). Follow the track on a map/GPS device.\n';
  result += '\n--- GPX DATA ---\n' + gpxData;
  return [{ json: { result } }];

// ============================================================
// ACTION: search_place
// ============================================================
} else if (action === 'search_place') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required.' } }];
  const limit = parseInt(input.limit) || 3;

  try {
    const res = await helpers.httpRequest({
      method: 'GET',
      url: ORS + '/geocode/search?api_key=' + API_KEY + '&text=' + encodeURIComponent(query) + '&size=' + limit,
      headers: { 'Accept': 'application/json' }
    });
    if (!res.features || res.features.length === 0) {
      return [{ json: { result: 'No places found for: ' + query } }];
    }
    let result = 'Places for "' + query + '":\n\n';
    for (const f of res.features) {
      const p = f.properties;
      const c = f.geometry.coordinates;
      result += '- ' + p.label + '\n';
      result += '  Coordinates: ' + c[1].toFixed(5) + ', ' + c[0].toFixed(5) + '\n';
      if (p.region) result += '  Region: ' + p.region + '\n';
      if (p.country) result += '  Country: ' + p.country + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Place search failed: ' + (err.message || err) } }];
  }

// ============================================================
// ACTION: find_pois
// ============================================================
} else if (action === 'find_pois') {
  const locationText = input.location;
  if (!locationText) return [{ json: { error: 'Parameter "location" is required.' } }];

  const geo = await geocode(locationText);
  if (!geo) return [{ json: { error: 'Could not geocode location: ' + locationText } }];

  const radius = Math.min(parseInt(input.radius) || 1500, 2000);

  // Verified category IDs from official categories.yml
  const catMap = {
    'alpine_hut': 101, 'camp_site': 103, 'bench': 162,
    'drinking_water': 166, 'shelter': 175, 'toilet': 179,
    'peak': 335, 'restaurant': 570, 'parking': 601,
    'picnic_site': 625, 'viewpoint': 627
  };
  const catNames = {};
  for (const [k, v] of Object.entries(catMap)) catNames[v] = k;

  // Default: outdoor-relevant (max 5 per request)
  let categoryIds = [101, 627, 166, 625, 335];
  if (input.categories) {
    const requested = input.categories.split(',').map(s => s.trim().toLowerCase());
    categoryIds = requested.map(c => catMap[c] || parseInt(c)).filter(id => !isNaN(id));
    if (categoryIds.length === 0) {
      return [{ json: { error: 'No valid categories. Available: ' + Object.keys(catMap).join(', ') } }];
    }
  }

  // ORS POIs API: max 5 category IDs per request
  let allFeatures = [];
  const batches = [];
  for (let i = 0; i < categoryIds.length; i += 5) {
    batches.push(categoryIds.slice(i, i + 5));
  }

  for (const batch of batches) {
    try {
      const poiData = await helpers.httpRequest({
        method: 'POST',
        url: ORS + '/pois',
        headers: ORS_H,
        body: JSON.stringify({
          request: 'pois',
          geometry: {
            geojson: { type: 'Point', coordinates: [geo.lon, geo.lat] },
            buffer: radius
          },
          filters: { category_ids: batch },
          limit: 20,
          sortby: 'distance'
        })
      });
      if (poiData.features) allFeatures = allFeatures.concat(poiData.features);
    } catch (err) {
      // Continue with other batches
    }
  }

  // Sort all results by distance
  allFeatures.sort((a, b) => (a.properties?.distance || 9999) - (b.properties?.distance || 9999));
  allFeatures = allFeatures.slice(0, 20);

  if (allFeatures.length === 0) {
    return [{ json: { result: 'No points of interest found near ' + geo.name + ' (radius: ' + radius + 'm)' } }];
  }

  let result = 'POIs near ' + geo.name + ' (radius ' + radius + 'm, ' + allFeatures.length + ' found):\n\n';
  for (const f of allFeatures) {
    const p = f.properties || {};
    const c = f.geometry.coordinates;
    const name = (p.osm_tags && p.osm_tags.name) || 'Unnamed';
    const dist = p.distance != null ? Math.round(p.distance) + 'm' : '?';
    // Try to identify category from the response
    let catStr = '';
    if (p.category_ids && typeof p.category_ids === 'object') {
      catStr = Object.keys(p.category_ids).map(id => catNames[id] || id).join(', ');
    } else if (p.category_ids) {
      catStr = String(p.category_ids);
    }
    result += '- ' + name + ' (' + catStr + ') — ' + dist + '\n';
    result += '  Coordinates: ' + c[1].toFixed(5) + ', ' + c[0].toFixed(5) + '\n';
    if (p.osm_tags && p.osm_tags.ele) result += '  Elevation: ' + p.osm_tags.ele + 'm\n';
    if (p.osm_tags && p.osm_tags.opening_hours) result += '  Hours: ' + p.osm_tags.opening_hours + '\n';
    result += '\n';
  }
  return [{ json: { result } }];

// ============================================================
// ACTION: get_elevation_profile
// ============================================================
} else if (action === 'get_elevation_profile') {
  const startText = input.start;
  const endText = input.end;
  if (!startText || !endText) return [{ json: { error: 'Parameters "start" and "end" are required.' } }];

  const geo = await geocodeMulti(startText, endText, input.waypoints);
  if (geo.error) return [{ json: { error: geo.error } }];

  // Use ORS Directions with elevation: true for full route profile
  let routeData;
  try {
    routeData = await helpers.httpRequest({
      method: 'POST',
      url: ORS + '/v2/directions/foot-hiking/geojson',
      headers: ORS_H,
      body: JSON.stringify({
        coordinates: geo.coords,
        elevation: true
      })
    });
  } catch (err) {
    return [{ json: { error: 'Elevation request failed: ' + (err.message || err) } }];
  }

  let elevations = [];
  let totalDist = 0;
  let totalGainAPI = 0;
  let totalLossAPI = 0;
  try {
    const feat = routeData.features[0];
    const coords = feat.geometry.coordinates;
    elevations = coords.map(c => c[2]);
    const summary = feat.properties.summary;
    if (summary) {
      totalDist = summary.distance || 0;
      totalGainAPI = summary.ascent || 0;
      totalLossAPI = summary.descent || 0;
    }
  } catch (e) {
    return [{ json: { error: 'Could not parse elevation data.' } }];
  }

  if (elevations.length === 0) {
    return [{ json: { error: 'No elevation data returned.' } }];
  }

  const minEle = Math.round(Math.min(...elevations));
  const maxEle = Math.round(Math.max(...elevations));
  const avgEle = Math.round(elevations.reduce((a, b) => a + b, 0) / elevations.length);
  const distKm = (totalDist / 1000).toFixed(1);

  // Calculate ascent/descent from data points (API summary may not include them)
  let totalGain = 0;
  let totalLoss = 0;
  for (let i = 1; i < elevations.length; i++) {
    const diff = elevations[i] - elevations[i - 1];
    if (diff > 0) totalGain += diff;
    else totalLoss += Math.abs(diff);
  }
  const ascent = totalGainAPI > 0 ? Math.round(totalGainAPI) : Math.round(totalGain);
  const descent = totalLossAPI > 0 ? Math.round(totalLossAPI) : Math.round(totalLoss);

  let result = 'Elevation Profile: ' + geo.startGeo.name + ' \u2192 ' + geo.endGeo.name + '\n\n';
  result += 'Distance: ' + distKm + ' km\n';
  result += 'Minimum elevation: ' + minEle + ' m\n';
  result += 'Maximum elevation: ' + maxEle + ' m\n';
  result += 'Average elevation: ' + avgEle + ' m\n';
  result += 'Total ascent: ' + ascent + ' m\n';
  result += 'Total descent: ' + descent + ' m\n';
  result += 'Data points: ' + elevations.length + '\n';

  // ASCII elevation chart
  const steps = 20;
  const range = maxEle - minEle || 1;
  const bucketSize = Math.ceil(elevations.length / steps);
  result += '\nProfile (vertical: elevation, horizontal: distance):\n';
  const chartRows = 8;
  const buckets = [];
  for (let i = 0; i < steps && i * bucketSize < elevations.length; i++) {
    const slice = elevations.slice(i * bucketSize, (i + 1) * bucketSize);
    buckets.push(Math.round(slice.reduce((a, b) => a + b, 0) / slice.length));
  }
  for (let row = chartRows; row >= 1; row--) {
    const threshold = minEle + (range * row / chartRows);
    let line = '';
    for (const b of buckets) {
      line += b >= threshold ? '\u2588' : ' ';
    }
    result += '  ' + line + '\n';
  }
  result += '  ' + minEle + 'm' + ' '.repeat(Math.max(0, buckets.length - String(minEle).length - String(maxEle).length - 2)) + maxEle + 'm\n';

  return [{ json: { result } }];

// ============================================================
// ACTION: get_isochrone
// ============================================================
} else if (action === 'get_isochrone') {
  const locationText = input.location;
  if (!locationText) return [{ json: { error: 'Parameter "location" is required.' } }];
  const timeMin = parseInt(input.time);
  if (!timeMin || timeMin <= 0) return [{ json: { error: 'Parameter "time" (minutes) is required and must be positive.' } }];

  const profile = input.profile || 'foot-hiking';
  const validProfiles = ['foot-hiking', 'foot-walking', 'cycling-regular', 'cycling-road', 'cycling-mountain', 'cycling-electric'];
  if (!validProfiles.includes(profile)) {
    return [{ json: { error: 'Invalid profile: ' + profile + '. Use: ' + validProfiles.join(', ') } }];
  }

  const geo = await geocode(locationText);
  if (!geo) return [{ json: { error: 'Could not geocode location: ' + locationText } }];

  let isoData;
  try {
    isoData = await helpers.httpRequest({
      method: 'POST',
      url: ORS + '/v2/isochrones/' + profile,
      headers: ORS_H,
      body: JSON.stringify({
        locations: [[geo.lon, geo.lat]],
        range: [timeMin * 60]
      })
    });
  } catch (err) {
    return [{ json: { error: 'Isochrone request failed: ' + (err.message || err) } }];
  }

  if (!isoData.features || isoData.features.length === 0) {
    return [{ json: { error: 'No isochrone data returned.' } }];
  }

  const feature = isoData.features[0];
  const props = feature.properties || {};
  const coords = feature.geometry.coordinates[0] || [];

  // Calculate bounding box and approximate area
  let minLat = 90, maxLat = -90, minLon = 180, maxLon = -180;
  for (const c of coords) {
    if (c[0] < minLon) minLon = c[0];
    if (c[0] > maxLon) maxLon = c[0];
    if (c[1] < minLat) minLat = c[1];
    if (c[1] > maxLat) maxLat = c[1];
  }

  // Approximate area using Shoelace formula on the polygon
  let area = 0;
  for (let i = 0; i < coords.length - 1; i++) {
    const [x1, y1] = coords[i];
    const [x2, y2] = coords[i + 1];
    area += x1 * y2 - x2 * y1;
  }
  area = Math.abs(area) / 2;
  // Convert from degree^2 to km^2 (approximate at mid-latitude)
  const midLat = (minLat + maxLat) / 2;
  const degToKmLat = 111.32;
  const degToKmLon = 111.32 * Math.cos(midLat * Math.PI / 180);
  const areaKm2 = (area * degToKmLat * degToKmLon).toFixed(1);

  // Max reach in each direction
  const reachNS = ((maxLat - minLat) * degToKmLat).toFixed(1);
  const reachEW = ((maxLon - minLon) * degToKmLon).toFixed(1);

  let result = 'Isochrone from ' + geo.name + '\n';
  result += 'Profile: ' + profile + '\n';
  result += 'Time: ' + timeMin + ' minutes\n\n';
  result += 'Reachable area: ~' + areaKm2 + ' km²\n';
  result += 'Max reach N-S: ~' + reachNS + ' km\n';
  result += 'Max reach E-W: ~' + reachEW + ' km\n';
  result += 'Bounding box: ' + minLat.toFixed(4) + ',' + minLon.toFixed(4) + ' → ' + maxLat.toFixed(4) + ',' + maxLon.toFixed(4) + '\n';
  if (props.area) result += 'Area (API): ' + (props.area / 1000000).toFixed(1) + ' km²\n';

  return [{ json: { result } }];

// ============================================================
// ACTION: optimize_route
// ============================================================
} else if (action === 'optimize_route') {
  const locationsText = input.locations;
  if (!locationsText) return [{ json: { error: 'Parameter "locations" is required (semicolon-separated, min 3).' } }];

  const locTexts = locationsText.split(';').map(s => s.trim()).filter(s => s);
  if (locTexts.length < 3) {
    return [{ json: { error: 'At least 3 locations are required for route optimization.' } }];
  }

  const profile = input.profile || 'foot-hiking';
  const validProfiles = ['foot-hiking', 'foot-walking', 'cycling-regular', 'cycling-road', 'cycling-mountain', 'cycling-electric', 'driving-car'];
  if (!validProfiles.includes(profile)) {
    return [{ json: { error: 'Invalid profile: ' + profile + '. Use: ' + validProfiles.join(', ') } }];
  }

  const startFixed = input.start_fixed !== 'false' && input.start_fixed !== false;
  const endFixed = input.end_fixed === 'true' || input.end_fixed === true;

  // Geocode all locations
  const geos = [];
  for (const loc of locTexts) {
    const g = await geocode(loc);
    if (!g) return [{ json: { error: 'Could not geocode location: ' + loc } }];
    geos.push(g);
  }

  // Build VROOM optimization request
  const jobs = geos.map((g, i) => {
    // Skip first if start_fixed, skip last if end_fixed
    if (startFixed && i === 0) return null;
    if (endFixed && i === geos.length - 1) return null;
    return {
      id: i,
      location: [g.lon, g.lat],
      description: g.name
    };
  }).filter(j => j !== null);

  const vehicle = {
    id: 0,
    profile: profile,
    start: [geos[0].lon, geos[0].lat]
  };
  if (endFixed) {
    vehicle.end = [geos[geos.length - 1].lon, geos[geos.length - 1].lat];
  }

  let optData;
  try {
    optData = await helpers.httpRequest({
      method: 'POST',
      url: ORS + '/optimization',
      headers: ORS_H,
      body: JSON.stringify({
        jobs: jobs,
        vehicles: [vehicle]
      })
    });
  } catch (err) {
    return [{ json: { error: 'Route optimization failed: ' + (err.message || err) } }];
  }

  if (!optData.routes || optData.routes.length === 0) {
    return [{ json: { error: 'Optimization returned no result.' } }];
  }

  const optRoute = optData.routes[0];
  const steps = optRoute.steps || [];

  let result = 'Optimized Route Order:\n\n';
  let stepNum = 1;
  for (const step of steps) {
    if (step.type === 'start') {
      result += stepNum + '. START: ' + geos[0].name + '\n';
      stepNum++;
    } else if (step.type === 'job') {
      const jobGeo = geos[step.job];
      result += stepNum + '. ' + (jobGeo ? jobGeo.name : 'Location ' + step.job) + '\n';
      stepNum++;
    } else if (step.type === 'end') {
      result += stepNum + '. END: ' + (endFixed ? geos[geos.length - 1].name : geos[0].name) + '\n';
      stepNum++;
    }
  }

  const totalDist = (optRoute.distance / 1000).toFixed(1);
  const totalDur = fmtDuration(optRoute.duration);
  result += '\nTotal distance: ' + totalDist + ' km\n';
  result += 'Total duration: ' + totalDur + '\n';

  if (optData.summary) {
    const s = optData.summary;
    if (s.unassigned > 0) result += '\nWarning: ' + s.unassigned + ' location(s) could not be reached.\n';
  }

  return [{ json: { result } }];

// ============================================================
// UNKNOWN ACTION
// ============================================================
} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use plan_route, plan_route_outdoor, search_place, find_pois, get_elevation_profile, get_isochrone, or optimize_route.' } }];
}
